#!/bin/bash

# AWS Credentials
AWS_ACCESS_KEY_ID="<your-access-key>"
AWS_SECRET_ACCESS_KEY="<your-secret-access-key>"
AWS_DEFAULT_REGION="<your-region>"

# AWS CLI Profile
AWS_PROFILE="default"

# AWS ECR Repository
AWS_ECR_REPOSITORY="<your-ecr-repository>"

# Docker Image Tag
DOCKER_IMAGE_TAG="<your-docker-image-tag>"

# AWS ECS Cluster
AWS_ECS_CLUSTER="<your-ecs-cluster>"

# AWS ECS Service
AWS_ECS_SERVICE="<your-ecs-service>"

# Authenticate with AWS
